with:
  if generator:
                  # Special handling for predicates with multiple objects where the
                  # generated phrase already contains the predicate description.
                  # For example, for multiple leaders we want "is led by X and Y"
                  # instead of "is led by X and is led by Y". The same applies to
                  # headquarters, where we prefer "has headquarters at X and Y".
                  if pred == "leader" and len(objs) > 1:
                      phrase = "is led by " + " and ".join(objs)
                  elif pred == "headquarter" and len(objs) > 1:
                      phrase = "has headquarters at " + " and ".join(objs)
                  elif len(objs) == 1:
                      phrase = generator(objs[0])
                  else:
                      subphrases = [generator(o) for o in objs]
                      phrase = " and ".join(subphrases)
